 1	import React, { FC } from 'react';
 2	
 3	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { FlexItem, Tooltip } from '@patternfly/react-core';
 6	import { CheckCircleIcon, WarningTriangleIcon } from '@patternfly/react-icons';
 7	
 8	import { SERVICE_TYPES } from '../constants';
 9	import { isLoadBalancerBonded } from '../useSSHCommand';
10	
11	type SSHServiceStateIconProps = {
12	  sshService: IoK8sApiCoreV1Service;
13	  sshServiceLoaded?: boolean;
14	};
15	
16	const SSHServiceStateIcon: FC<SSHServiceStateIconProps> = ({ sshService, sshServiceLoaded }) => {
17	  const { t } = useKubevirtTranslation();
18	
19	  if (sshService?.spec?.type !== SERVICE_TYPES.LOAD_BALANCER) return null;
20	
21	  if (!sshServiceLoaded) return null;
22	
23	  return (
24	    <FlexItem>
25	      {!isLoadBalancerBonded(sshService) ? (
26	        <Tooltip content={t('This process can take 1-2 minutes to complete.')}>
27	          <div>
28	            <WarningTriangleIcon color="var(--pf-t--global--color--status--warning--default)" />{' '}
29	            {t('In progress')}{' '}
30	          </div>
31	        </Tooltip>
32	      ) : (
33	        <div>
34	          <CheckCircleIcon color="var(--pf-t--global--color--status--success--default)" /> {t('Ready')}{' '}
35	        </div>
36	      )}
37	    </FlexItem>
38	  );
39	};
40	
41	export default SSHServiceStateIcon;

